const response = $input.first().json;
const summaries = response.data || [];

const now = new Date();
const weekStart = new Date(now);
weekStart.setDate(now.getDate() - 7);

const dateRange = `${weekStart.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })} – ${now.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' })}`;

// Aggregate all user stats
let totalCreated = 0, totalCompleted = 0, totalOverdue = 0, totalPending = 0;
for (const s of summaries) {
  totalCreated += s.created_this_week || 0;
  totalCompleted += s.completed_this_week || 0;
  totalOverdue += s.overdue_tasks || 0;
  totalPending += s.pending_tasks || 0;
}

const rate = totalCreated > 0 ? Math.round((totalCompleted / totalCreated) * 100) : 0;
const rateBar = '█'.repeat(Math.floor(rate / 10)) + '░'.repeat(10 - Math.floor(rate / 10));

const html = `<!DOCTYPE html>
<html>
<head>
<meta charset="utf-8">
<style>
  body { font-family: -apple-system, BlinkMacSystemFont, 'Inter', sans-serif; background: #0A0A0F; color: #F5F5F7; margin: 0; padding: 0; }
  .container { max-width: 600px; margin: 0 auto; padding: 32px 24px; }
  .header { background: linear-gradient(135deg, #1A0533, #0F0F1A); border-radius: 16px; padding: 32px; margin-bottom: 24px; border: 1px solid #2A2A35; }
  .logo { font-size: 24px; font-weight: 800; color: #F5F5F7; letter-spacing: -0.5px; margin-bottom: 4px; }
  .period { font-size: 13px; color: #8E8E9A; margin-top: 8px; }
  .stat-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 12px; margin: 24px 0; }
  .stat { background: #141419; border: 1px solid #2A2A35; border-radius: 12px; padding: 20px; text-align: center; }
  .stat-number { font-size: 32px; font-weight: 700; letter-spacing: -1px; }
  .stat-label { font-size: 11px; color: #8E8E9A; text-transform: uppercase; letter-spacing: 0.8px; margin-top: 4px; font-weight: 500; }
  .rate-bar { font-family: monospace; color: #8B5CF6; font-size: 14px; letter-spacing: 2px; }
  .section-title { font-size: 11px; color: #55555F; text-transform: uppercase; letter-spacing: 1px; font-weight: 600; margin: 24px 0 12px; }
  .footer { text-align: center; font-size: 12px; color: #55555F; margin-top: 32px; padding-top: 24px; border-top: 1px solid #1E1E28; }
  a { color: #8B5CF6; text-decoration: none; }
  .cta { display: inline-block; background: linear-gradient(90deg, #8B5CF6, #06B6D4); color: #fff; font-weight: 600; padding: 14px 28px; border-radius: 999px; text-decoration: none; margin-top: 16px; font-size: 14px; }
</style>
</head>
<body>
<div class="container">
  <div class="header">
    <div class="logo">⚡ Flux Tasks</div>
    <div style="font-size:22px;font-weight:700;margin-top:12px;">Your Weekly Digest</div>
    <div class="period">${dateRange}</div>
  </div>

  <div class="section-title">This week at a glance</div>
  <div class="stat-grid">
    <div class="stat"><div class="stat-number" style="color:#06B6D4">${totalCreated}</div><div class="stat-label">Tasks Created</div></div>
    <div class="stat"><div class="stat-number" style="color:#10B981">${totalCompleted}</div><div class="stat-label">Completed</div></div>
    <div class="stat"><div class="stat-number" style="color:#EF4444">${totalOverdue}</div><div class="stat-label">Overdue</div></div>
    <div class="stat"><div class="stat-number" style="color:#8E8E9A">${totalPending}</div><div class="stat-label">Still Pending</div></div>
  </div>

  <div class="section-title">Completion Rate</div>
  <div style="background:#141419;border:1px solid #2A2A35;border-radius:12px;padding:20px;">
    <div style="font-size:36px;font-weight:700;color:#8B5CF6;margin-bottom:8px;">${rate}%</div>
    <div class="rate-bar">${rateBar}</div>
    <div style="font-size:12px;color:#55555F;margin-top:8px;">${totalCompleted} of ${totalCreated} tasks completed this week</div>
  </div>

  <div style="text-align:center;margin-top:24px;">
    <a href="#" class="cta">Open Flux Tasks →</a>
  </div>

  <div class="footer">
    <p>Flux Tasks · BuildableLabs Assignment</p>
    <p>Automated by n8n Cloud ⚡</p>
  </div>
</div>
</body>
</html>`;

return [{ json: { html, subject: `📋 Weekly Digest · ${dateRange}`, dateRange, totalCreated, totalCompleted, rate } }];
